local trace = print local TD = TD.td1madao["ydj_dst_td1madao"] local function createStrParam(...)     local argNum = select("#", ...)     local str = ""     for i = 1, argNum do         str = str .. tostring(select(i, ...)) .. ","     end     return str end TD.createFn("debug", function(str, send, player)     if not TD.CONST.DEBUG then         return     end     if not TD.isStr(str) then         str = "{}"     end     local action = STRINGS.TD1MADAO[TD.holder("%s_RECEIVE")]     if send then         action = STRINGS.TD1MADAO[TD.holder("%s_SEND")]     end     TD.server(function()         trace(string.format("[%s]%s,%s:%s", STRINGS.TD1MADAO[TD.holder("%s_SERVER")], tostring(player or TD.GetPlayer()), action, str))     end, function()         trace(string.format("[%s]%s,%s:%s", STRINGS.TD1MADAO[TD.holder("%s_CLIENT")], tostring(player or TD.GetPlayer()), action, str))     end) end) TD.createFn("printTab", function(tab, str)     if not TD.isTab(tab) then         return     end     if not TD.isStr(str) then         str = ""     end     trace(str, "************************************", tab)     TD.fori(tab or {}, function(k, v)         trace("k=", k, " v=", v)     end) end) TD.createFn("printWhere", function()     local info = debug.getinfo(2, "nlS")     trace("Where am I:", info.source:sub(2), info.name, info.currentline) end) 